import pytest
import threading
import time
from cache import Cache

def test_concurrent_puts():
    c = Cache(1000)
    errors = []

    def writer(prefix, count):
        try:
            for i in range(count):
                c.put(f"{prefix}_{i}", i)
        except Exception as e:
            errors.append(str(e))

    threads = [threading.Thread(target=writer, args=(f"t{i}", 100)) for i in range(5)]
    for t in threads: t.start()
    for t in threads: t.join()

    assert not errors, f"Errors during concurrent writes: {errors}"
    assert c.size() <= 1000

def test_concurrent_get_put():
    c = Cache(100)
    for i in range(50):
        c.put(f"key_{i}", i)

    errors = []
    def reader():
        try:
            for i in range(100):
                c.get(f"key_{i % 50}")
        except Exception as e:
            errors.append(str(e))

    def writer():
        try:
            for i in range(50, 100):
                c.put(f"key_{i}", i)
        except Exception as e:
            errors.append(str(e))

    threads = [threading.Thread(target=reader) for _ in range(3)]
    threads.append(threading.Thread(target=writer))
    for t in threads: t.start()
    for t in threads: t.join()

    assert not errors, f"Errors: {errors}"

def test_concurrent_eviction():
    c = Cache(10)
    errors = []

    def writer():
        try:
            for i in range(100):
                c.put(f"key_{i}", i)
        except Exception as e:
            errors.append(str(e))

    threads = [threading.Thread(target=writer) for _ in range(3)]
    for t in threads: t.start()
    for t in threads: t.join()

    assert not errors, f"Errors during eviction: {errors}"
    assert c.size() <= 10
